#include <stdio.h>
#include <stdlib.h>

typedef struct {int parent; int size;} DSU;

int find(DSU *d, int x) {
    if (d[x].parent != x) d[x].parent = find(d, d[x].parent);
    return d[x].parent;
}

void unite(DSU *d, int a, int b) {
    int ra = find(d, a), rb = find(d, b);
    if (ra == rb) return;
    if (d[ra].size < d[rb].size) {
        d[ra].parent = rb;
        d[rb].size += d[ra].size;
    } else {
        d[rb].parent = ra;
        d[ra].size += d[rb].size;
    }
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, M; scanf("%d %d", &N, &M);
        DSU *dsu = (DSU*)malloc((N + 1) * sizeof(DSU));
        for (int i = 1; i <= N; ++i) { dsu[i].parent = i; dsu[i].size = 1; }
        for (int i = 0; i < M; ++i) {
            int u, v; scanf("%d %d", &u, &v);
            unite(dsu, u, v);
        }
        int components = 0;
        for (int i = 1; i <= N; ++i) if (find(dsu, i) == i) ++components;
        printf("%d\n", components);
        free(dsu);
    }
    return 0;
}

