#include <bits/stdc++.h>
using namespace std;

struct DSU {
    vector<int> parent, sz;
    DSU(int n = 0) { init(n); }
    void init(int n) {
        parent.resize(n + 1);
        sz.assign(n + 1, 1);
        iota(parent.begin(), parent.end(), 0);
    }
    int find(int x) { return parent[x] == x ? x : parent[x] = find(parent[x]); }
    void unite(int a, int b) {
        a = find(a); b = find(b);
        if (a == b) return;
        if (sz[a] < sz[b]) swap(a, b);
        parent[b] = a; sz[a] += sz[b];
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if (!(cin >> T)) return 0;
    while (T--) {
        int N, M; cin >> N >> M;
        DSU dsu(N);
        for (int i = 0; i < M; ++i) {
            int u, v; cin >> u >> v;
            dsu.unite(u, v);
        }
        int components = 0;
        for (int i = 1; i <= N; ++i) if (dsu.find(i) == i) ++components;
        cout << components << '\n';
    }
    return 0;
}

