import sys

def find(parent, x):
    while parent[x] != x:
        parent[x] = parent[parent[x]]
        x = parent[x]
    return x

def union(parent, size, a, b):
    ra, rb = find(parent, a), find(parent, b)
    if ra == rb:
        return
    if size[ra] < size[rb]:
        ra, rb = rb, ra
    parent[rb] = ra
    size[ra] += size[rb]

def main():
    data = sys.stdin.buffer.read().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); M = int(next(it))
        parent = list(range(N + 1))
        size = [1] * (N + 1)
        for _ in range(M):
            u = int(next(it)); v = int(next(it))
            union(parent, size, u, v)
        components = sum(1 for i in range(1, N + 1) if find(parent, i) == i)
        out_lines.append(str(components))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

